challenge_result.investigation_instruction:
{
  "plans": [
    {
      "hypothesis_id": "h1",
      "hypothesis_statement": "The SMF is failing to correctly install N4 session rules on the UPF, resulting in a complete outage of the user data plane. Although the SMF reports active PDU sessions, the UPF has no forwarding rules and drops all GTP packets.",
      "primary_suspect_nf": "smf",
      "probes": [
        {
          "tool": "get_nf_metrics",
          "args_hint": "smf",
          "expected_if_hypothesis_holds": "A high or increasing value for a metric like `pfcp.session_establishment.failed` on the SMF.",
          "falsifying_observation": "The `pfcp.session_establishment.failed` counter on the SMF is 0. This directly contradicts the hypothesis that the SMF is failing to install rules."
        },
        {
          "tool": "get_dp_quality_gauges",
          "args_hint": "window_seconds=60",
          "expected_if_hypothesis_holds": "The gNB is sending GTP-U packets (`ran.gtpu.tx.packets_per_second` > 0), but the UPF is not receiving them (`upf.n3.rx.packets_per_second` == 0), consistent with a drop or black-hole at the UPF.",
          "falsifying_observation": "The gNB is not sending any GTP-U packets (`ran.gtpu.tx.packets_per_second` == 0). This would indicate the problem is upstream of the SMF/UPF N4 interface."
        },
        {
          "tool": "get_network_status",
          "args_hint": "smf, upf",
          "expected_if_hypothesis_holds": "Both the `smf` and `upf` containers are in a 'running' state, as the hypothesis concerns a protocol-level failure, not a container crash.",
          "falsifying_observation": "Either the `smf` or `upf` container is in an 'exited' state. This would point to a simpler container crash as the root cause, not a rule installation failure."
        }
      ],
      "notes": "This plan tests the N4 failure hypothesis by checking for direct evidence of PFCP failures on the SMF, verifying the 'no traffic' symptom by checking upstream traffic from the gNB, and ruling out a simple container crash."
    },
    {
      "hypothesis_id": "h2",
      "hypothesis_statement": "The P-CSCF is rejecting VoNR call setups because it cannot communicate with the PCF to obtain QoS policy authorization over the Rx interface. This is causing SIP errors and preventing any calls from being established.",
      "primary_suspect_nf": "pcscf",
      "probes": [
        {
          "tool": "measure_rtt",
          "args_hint": "from='pcscf', to_ip='pcf_ip'",
          "expected_if_hypothesis_holds": "High RTT or 100% packet loss, indicating a network partition or problem on the PCF.",
          "falsifying_observation": "Clean, low RTT (<5ms). This proves basic network connectivity is fine, suggesting the problem is at the application layer (e.g., config, credentials, PCF logic)."
        },
        {
          "tool": "measure_rtt",
          "args_hint": "from='smf', to_ip='pcf_ip'",
          "expected_if_hypothesis_holds": "Clean, low RTT (<5ms). If this succeeds while the P-CSCF->PCF ping fails, it isolates the problem to the P-CSCF or its immediate network path.",
          "falsifying_observation": "High RTT or 100% packet loss. If the PCF is unreachable from multiple sources, it becomes the primary suspect, falsifying the hypothesis that the P-CSCF is the source of the communication failure."
        },
        {
          "tool": "get_nf_metrics",
          "args_hint": "pcscf",
          "expected_if_hypothesis_holds": "A high or increasing value for P-CSCF's `http_client.conn_failed` metric, confirming that it is failing to connect to the PCF over the Rx interface.",
          "falsifying_observation": "The `http_client.conn_failed` metric is 0. This implies the P-CSCF is either not attempting to connect or is succeeding, meaning the SIP rejections have a different cause."
        }
      ],
      "notes": "This is a triangulation plan. It first checks the P-CSCF->PCF path as suggested by the hypothesis. It then uses the SMF as a second vantage point to determine if the PCF is broadly unreachable, which would falsify the P-CSCF-specific nature of the hypothesis. Finally, it checks for application-level connection errors."
    },
    {
      "hypothesis_id": "h3",
      "hypothesis_statement": "The UPF has experienced an internal failure and is black-holing all N3 and N9 traffic. This explains the complete lack of GTP traffic, but the root cause is within the UPF itself, not the N4 control interface.",
      "primary_suspect_nf": "upf",
      "probes": [
        {
          "tool": "get_network_status",
          "args_hint": "upf",
          "expected_if_hypothesis_holds": "The `upf` container is in a 'running' state, as 'black-holing' implies a misbehaving but active process.",
          "falsifying_observation": "The `upf` container is in an 'exited' state, which would mean it crashed rather than experienced an 'internal failure' of the black-holing type."
        },
        {
          "tool": "get_nf_metrics",
          "args_hint": "upf",
          "expected_if_hypothesis_holds": "High resource usage metrics for the `upf`, such as `container.cpu.usage` or `container.memory.usage`, which are common causes of internal failures.",
          "falsifying_observation": "Normal resource utilization for the `upf`. This would suggest the failure is not related to resource exhaustion but perhaps a software deadlock or other bug."
        },
        {
          "tool": "get_dp_quality_gauges",
          "args_hint": "window_seconds=60",
          "expected_if_hypothesis_holds": "`ran.gtpu.tx.packets_per_second` is > 0 while `upf.n3.rx.packets_per_second` is 0, which confirms traffic is being sent but not received/processed by the UPF.",
          "falsifying_observation": "`ran.gtpu.tx.packets_per_second` is 0. If the gNB isn't sending traffic, the UPF cannot be black-holing it. This would point the problem upstream."
        }
      ],
      "notes": "This plan aims to falsify the 'internal failure' hypothesis by checking for the most common failure modes: a container crash or resource exhaustion. It also verifies the precondition for the 'black-holing' claim by ensuring traffic is actually being sent to the UPF from upstream."
    }
  ]
}

